{"command": "gh repo list Ai-Whisperers --limit 50 --json name,description 2>/dev/null | python3 -c "
import json, sys
repos = json.load(sys.stdin)
for r in repos:
    name = r['name'].lower()
    desc = (r['description'] or '').lower()
    if 'nico' in name or 'nico' in desc or 'portfolio' in name and 'power' in desc:
        print(f\"{r['name']:35s} | {r['description'] or '(no desc)'}\")
"", "timeout": 10}

{"command": "gh repo list weissvanderpol --limit 30 --json name,description 2>/dev/null | python3 -c "
import json, sys
repos = json.load(sys.stdin)
for r in repos:
    name = r['name'].lower()
    desc = (r['description'] or '').lower()
    if 'nico' in name or ('power' in desc and ('bi' in desc or 'dash' in desc)):
        print(f\"{r['name']:35s} | {r['description'] or '(no desc)'}\")
"", "timeout": 10}

